"""
main.py — FastAPI backend for DATAVERSE AI
Connects the React/Next.js frontend to existing Python logic files.

SETUP:
1. Place this file in your project root (same folder as data_cleaner.py, chatbot.py, etc.)
2. Activate your virtual environment:
       .venv\\Scripts\\activate
3. Install FastAPI if not already installed:
       pip install fastapi uvicorn python-multipart
4. Run with:
       uvicorn main:app --reload --port 8001

Your React frontend .env.local should have:
       NEXT_PUBLIC_API_URL=http://127.0.0.1:8001
"""

import io
from typing import Optional

import numpy as np
import pandas as pd
from fastapi import FastAPI, File, HTTPException, UploadFile
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import StreamingResponse
from pydantic import BaseModel

# ── Import your existing logic files ──────────────────────────────────────────
from data_cleaner import DataCleaner
from insights_generator import InsightsGenerator
from advanced_stats import AdvancedStatistics
from transformation_pipeline import TransformationPipeline
from chatbot_v2 import LLaMAChat

# ── App setup ──────────────────────────────────────────────────────────────────
app = FastAPI(title="DATAVERSE AI API", version="1.0.0")

app.add_middleware(
    CORSMiddleware,
    allow_origins=["http://localhost:3000", "http://127.0.0.1:3000"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

# ── In-memory store (replaces Streamlit session_state) ────────────────────────
_store: dict = {
    "uploaded_df": None,
    "cleaned_df": None,
    "cleaning_report": None,
    "insights": None,
}

_chatbot: Optional[LLaMAChat] = None


def get_chatbot() -> LLaMAChat:
    global _chatbot
    if _chatbot is None:
        _chatbot = LLaMAChat()
    return _chatbot


def df_to_json(df: pd.DataFrame) -> dict:
    """Convert DataFrame to a JSON-safe dict."""
    return {
        "rows": df.shape[0],
        "columns": df.shape[1],
        "column_names": list(df.columns),
        "dtypes": {col: str(dtype) for col, dtype in df.dtypes.items()},
        "missing_values": df.isnull().sum().to_dict(),
        "preview": df.head(10).replace({np.nan: None}).to_dict(orient="records"),
        "summary": (
            df.describe(include="all").replace({np.nan: None}).to_dict()
            if len(df.columns) > 0
            else {}
        ),
    }


def load_dataframe(file: UploadFile) -> pd.DataFrame:
    """Load uploaded file into a DataFrame based on extension."""
    contents = file.file.read()
    name = file.filename or ""

    if name.endswith(".csv"):
        return pd.read_csv(io.BytesIO(contents))
    elif name.endswith((".xlsx", ".xls")):
        return pd.read_excel(io.BytesIO(contents))
    elif name.endswith(".json"):
        return pd.read_json(io.BytesIO(contents))
    elif name.endswith(".parquet"):
        return pd.read_parquet(io.BytesIO(contents))
    else:
        raise HTTPException(status_code=400, detail=f"Unsupported file format: {name}")


# ══════════════════════════════════════════════════════════════════════════════
# ROUTES
# ══════════════════════════════════════════════════════════════════════════════

@app.get("/")
def root():
    return {"status": "DATAVERSE AI backend is running ✅"}


@app.get("/health")
def health():
    return {"status": "ok"}


# ── 1. Upload ──────────────────────────────────────────────────────────────────

@app.post("/upload")
async def upload_file(file: UploadFile = File(...)):
    """
    POST /upload
    Accepts: multipart/form-data with field 'file'
    Returns: file info + data preview
    """
    try:
        df = load_dataframe(file)

        # Reset store on new upload
        _store["uploaded_df"] = df
        _store["cleaned_df"] = None
        _store["cleaning_report"] = None
        _store["insights"] = None

        return {
            "message": "File uploaded successfully",
            "filename": file.filename,
            "data": df_to_json(df),
        }
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


@app.get("/data/preview")
def get_preview():
    """GET /data/preview — Returns preview of current dataset."""
    df = _store.get("cleaned_df") or _store.get("uploaded_df")
    if df is None:
        raise HTTPException(status_code=404, detail="No data uploaded yet")
    return df_to_json(df)


# ── 2. Clean ───────────────────────────────────────────────────────────────────

class CleanOptions(BaseModel):
    remove_duplicates: bool = True
    missing_strategy: str = "Auto"
    detect_outliers: bool = True
    normalize: bool = False


@app.post("/clean")
def clean_data(options: CleanOptions):
    """
    POST /clean
    Body: CleanOptions JSON
    Returns: before/after stats, cleaning report, cleaned data preview
    """
    df = _store.get("uploaded_df")
    if df is None:
        raise HTTPException(
            status_code=400, detail="No data uploaded. Please upload a file first."
        )

    try:
        cleaner = DataCleaner()
        cleaned_df, report = cleaner.clean_data(
            df.copy(),
            remove_duplicates=options.remove_duplicates,
            missing_strategy=options.missing_strategy,
            detect_outliers=options.detect_outliers,
            normalize=options.normalize,
        )

        _store["cleaned_df"] = cleaned_df
        _store["cleaning_report"] = report

        return {
            "message": "Data cleaned successfully",
            "before": {
                "rows": df.shape[0],
                "columns": df.shape[1],
                "missing": int(df.isnull().sum().sum()),
                "duplicates": int(df.duplicated().sum()),
            },
            "after": {
                "rows": cleaned_df.shape[0],
                "columns": cleaned_df.shape[1],
                "missing": int(cleaned_df.isnull().sum().sum()),
                "duplicates": int(cleaned_df.duplicated().sum()),
            },
            "report": report,
            "data": df_to_json(cleaned_df),
        }
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


@app.get("/clean/report")
def get_cleaning_report():
    """GET /clean/report — Returns the last cleaning report."""
    report = _store.get("cleaning_report")
    if report is None:
        raise HTTPException(status_code=404, detail="No cleaning report available")
    return report


# ── 3. Download ────────────────────────────────────────────────────────────────

@app.get("/download/csv")
def download_csv():
    df = _store.get("cleaned_df")
    if df is None:
        raise HTTPException(status_code=404, detail="No cleaned data available")
    stream = io.StringIO()
    df.to_csv(stream, index=False)
    return StreamingResponse(
        iter([stream.getvalue()]),
        media_type="text/csv",
        headers={"Content-Disposition": "attachment; filename=cleaned_data.csv"},
    )


@app.get("/download/excel")
def download_excel():
    df = _store.get("cleaned_df")
    if df is None:
        raise HTTPException(status_code=404, detail="No cleaned data available")
    buf = io.BytesIO()
    with pd.ExcelWriter(buf, engine="xlsxwriter") as writer:
        df.to_excel(writer, index=False)
    buf.seek(0)
    return StreamingResponse(
        buf,
        media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": "attachment; filename=cleaned_data.xlsx"},
    )


# ── 4. Insights ────────────────────────────────────────────────────────────────

@app.get("/insights")
def get_insights():
    """GET /insights — Generate statistical insights from the dataset."""
    df = _store.get("cleaned_df") or _store.get("uploaded_df")
    if df is None:
        raise HTTPException(status_code=400, detail="No data available")

    try:
        gen = InsightsGenerator()
        insights = gen.generate_insights(df)
        _store["insights"] = insights

        # Correlation matrix
        num_cols = df.select_dtypes(include=[np.number]).columns
        correlation = {}
        if len(num_cols) > 1:
            correlation = df[num_cols].corr().replace({np.nan: None}).to_dict()

        # Per-column stats
        col_stats = [
            {
                "name": col,
                "dtype": str(df[col].dtype),
                "null_count": int(df[col].isnull().sum()),
                "null_pct": round(df[col].isnull().mean() * 100, 2),
                "unique": int(df[col].nunique()),
            }
            for col in df.columns
        ]

        return {
            "insights": insights,
            "correlation": correlation,
            "column_stats": col_stats,
            "summary": df.describe(include="all").replace({np.nan: None}).to_dict(),
        }
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


