# ── 6. Visualize (chart data for Recharts) ─────────────────────────────────────

@app.get("/visualize/chart-data")
def get_chart_data():
    """
    GET /visualize/chart-data
    Returns pre-computed chart data that Recharts can render directly.
    """
    df = _store.get("cleaned_df") or _store.get("uploaded_df")
    if df is None:
        raise HTTPException(status_code=400, detail="No data available")

    num_cols = df.select_dtypes(include=[np.number]).columns.tolist()
    cat_cols = df.select_dtypes(include=["object", "category"]).columns.tolist()
    charts = {}

    # Histogram bins for numerical columns (first 5)
    for col in num_cols[:5]:
        counts, bin_edges = np.histogram(df[col].dropna(), bins=20)
        charts[f"histogram_{col}"] = {
            "type": "histogram",
            "column": col,
            "data": [
                {"bin": round(float(bin_edges[i]), 2), "count": int(counts[i])}
                for i in range(len(counts))
            ],
        }

    # Bar chart for categorical columns (first 3)
    for col in cat_cols[:3]:
        vc = df[col].value_counts().head(10)
        charts[f"bar_{col}"] = {
            "type": "bar",
            "column": col,
            "data": [{"label": str(k), "count": int(v)} for k, v in vc.items()],
        }

    # Scatter plot for first two numerical columns
    if len(num_cols) >= 2:
        sample = df[[num_cols[0], num_cols[1]]].dropna().head(500)
        charts["scatter"] = {
            "type": "scatter",
            "x": num_cols[0],
            "y": num_cols[1],
            "data": sample.replace({np.nan: None}).to_dict(orient="records"),
        }

    return {
        "charts": charts,
        "numerical_columns": num_cols,
        "categorical_columns": cat_cols,
    }


# ── 7. Transformation Pipeline ─────────────────────────────────────────────────

class TransformStep(BaseModel):
    type: str
    params: dict


class PipelineRequest(BaseModel):
    steps: list[TransformStep]


@app.post("/transform")
def run_pipeline(req: PipelineRequest):
    """
    POST /transform
    Body: { steps: [{ type: "filter_rows", params: {...} }, ...] }
    """
    df = _store.get("cleaned_df") or _store.get("uploaded_df")
    if df is None:
        raise HTTPException(status_code=400, detail="No data available")

    try:
        pipeline = TransformationPipeline()
        for step in req.steps:
            pipeline.add_transformation(step.type, step.params)

        transformed_df, log = pipeline.apply_pipeline(df.copy())
        _store["cleaned_df"] = transformed_df

        return {
            "message": "Pipeline executed successfully",
            "execution_log": log,
            "data": df_to_json(transformed_df),
        }
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


# ── 8. Chat ────────────────────────────────────────────────────────────────────

class ChatRequest(BaseModel):
    question: str


@app.post("/chat")
def chat(req: ChatRequest):
    """
    POST /chat
    Body: { question: "What are the main trends in this data?" }
    Returns: { response: "..." }
    """
    df = _store.get("cleaned_df") or _store.get("uploaded_df")
    if df is None:
        raise HTTPException(
            status_code=400,
            detail="No data uploaded yet. Please upload a file first.",
        )

    try:
        chatbot = get_chatbot()
        context = {
            "shape": df.shape,
            "columns": list(df.columns),
            "dtypes": {col: str(dtype) for col, dtype in df.dtypes.items()},
            "summary": (
                df.describe().replace({np.nan: None}).to_dict()
                if len(df.select_dtypes(include=[np.number]).columns) > 0
                else {}
            ),
            "missing_values": df.isnull().sum().to_dict(),
            "sample_data": df.head(3).replace({np.nan: None}).to_dict(),
        }

        response = chatbot.generate_response(req.question, context)
        return {"response": response}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))